SELECT provider_id
FROM provider_details
WHERE dns_over_https = 1;

SELECT COUNT(*) 
  FROM provider_details 
  WHERE dns_over_https = 1;

SELECT name 
FROM dot_providers 
WHERE tls_ports = 853;

SELECT DISTINCT supported_protocols 
FROM provider_details 
WHERE provider_id = 1;

SELECT MAX(spki_pin) AS max_spki_pin
FROM provider_details
WHERE dns_over_https = 1;

SELECT COUNT(*) AS count_of_providers
FROM provider_details
WHERE supported_protocols = 'DNS-over-TLS, DNS-over-HTTPS';

SELECT 
    (SELECT COUNT(provider_id) FROM dot_providers) AS total_providers,
    (SELECT COUNT(detail_id) FROM provider_details) AS total_details;

SELECT hostname_for_tls_authentication 
FROM dot_providers 
WHERE provider_id = 0;

SELECT 'DoT Service Providers' AS category, COUNT(provider_id) AS total FROM dot_providers
UNION ALL
SELECT 'Provider Details' AS category, COUNT(detail_id) AS total FROM provider_details;
